import{_ as s,C as t,o as h,c as m,j as e,a as n,E as i,a3 as c}from"./chunks/framework.CVjg771q.js";const P=JSON.parse('{"title":"太上老君说常清静经","description":"一部由大道落到清静工夫的短经。","frontmatter":{"title":"太上老君说常清静经","description":"一部由大道落到清静工夫的短经。","category":"guide","aliases":["清静经","常清静经","qingjing jing"],"source":["《太上老君说常清静经》"]},"headers":[],"relativePath":"daoism/starter-texts/qingjing-jing.md","filePath":"daoism/starter-texts/qingjing-jing.md","lastUpdated":1777883327000}'),g={name:"daoism/starter-texts/qingjing-jing.md"};function u(x,a,b,q,_,f){const r=t("DaoReadingPrelude"),o=t("DaoOriginalReading"),l=t("DaoLineGuide"),p=t("DaoTraditionAppendix"),d=t("DaoKeywordCards");return h(),m("div",null,[a[0]||(a[0]=e("h1",{id:"太上老君说常清静经",tabindex:"-1"},[n("太上老君说常清静经 "),e("a",{class:"header-anchor",href:"#太上老君说常清静经","aria-label":'Permalink to "太上老君说常清静经"'},"​")],-1)),i(r,{title:"先看大道如何落到清静工夫",summary:"这部经先从大道说起，再一路收回到人的心如何遣欲、观照、复归清静。第一次读时，最适合先抓住“道体总说、清浊动静、人心为何不静、观照工夫、真静得道”这几层。",points:[{label:"先读",text:"先顺着正文读一遍，感受从大道落到人心的路径。"},{label:"再辨",text:"留意清 / 浊、动 / 静、心 / 欲如何层层转进。"},{label:"后看",text:"最后再回到“常应常静”与“实无所得”的收束处。"}],hint:"正文偏义理与工夫，附录偏传承与护持；第一次读时，可先把正文读清，再独立看后面的传承附录。"}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[n("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),i(o,{paragraphs:["老君曰：","大道无形，生育天地；","大道无情，运行日月；","大道无名，长养万物；","吾不知其名，强名曰道。","夫道者：","有清有浊，有动有静；","天清地浊，天动地静；","男清女浊，男动女静；","降本流末，而生万物。","清者浊之源，动者静之基；","人能常清静，天地悉皆归。","夫人神好清，而心扰之；","人心好静，而欲牵之。","常能遣其欲，而心自静；","澄其心，而神自清；","自然六欲不生，三毒消灭。","所以不能者，","为心未澄，欲未遣也。","能遣之者：","内观其心，心无其心；","外观其形，形无其形；","远观其物，物无其物。","三者既悟，唯见於空。","观空亦空，空无所空；","所空既无，无无亦无；","无无既无，湛然常寂。","寂无所寂，欲岂能生？","欲既不生，即是真静。","真常应物，真常得性；","常应常静，常清静矣。","如此清静，渐入真道；","既入真道，名为得道；","虽名得道，实无所得；","为化众生，名为得道；","能悟之者，可传圣道。"]}),i(l,{lines:[{text:"大道无形，生育天地；大道无情，运行日月；大道无名，长养万物；吾不知其名，强名曰道。",tone:"道体 · 先开门",guide:"这一段先不要只读成抽象玄理，它是在说大道虽然不执形名，却始终生育、运行、长养万物。"},{text:"夫道者：有清有浊，有动有静……人能常清静，天地悉皆归。",tone:"生成 · 清浊动静",guide:"清与浊、动与静不是切开的两端，而是在同一流行里互为根柢，所以最后才会收回到“人能常清静”。"},{text:"夫人神好清，而心扰之；人心好静，而欲牵之……三者既悟，唯见於空。",tone:"工夫 · 先遣其欲",guide:"这一段最适合从自身经验去读：不是人不想静，而是心会自扰、欲会牵引，所以修持先落在澄心遣欲与观照。"},{text:"观空亦空……常应常静，常清静矣。",tone:"真静 · 不离应物",guide:"“真静”不是逃开世界，而是在应物之中仍不失其根，所以后面才说“真常应物，常应常静”。"},{text:"如此清静，渐入真道……能悟之者，可传圣道。",tone:"得道 · 无所得",guide:"经文最后既说“渐入真道”，又马上补上“实无所得”，提醒人不要把修行又执成新的占有。"}]}),a[2]||(a[2]=e("h2",{id:"【原典层】传承附录",tabindex:"-1"},[n("【原典层】传承附录 "),e("a",{class:"header-anchor",href:"#【原典层】传承附录","aria-label":'Permalink to "【原典层】传承附录"'},"​")],-1)),i(p,{description:"附录部分偏向传承谱系、护持与信受传统，和正文的义理工夫不同，适合独立成卷来读。",image:"https://www.fridolph.top/static/dao/qingjingjing.png","image-alt":"太上老君说常清静经",entries:[{speaker:"葛翁",role:"传授谱系",text:"吾得真道，曾诵此经万遍。此经是天人所习，不传下士。吾昔受之于东华帝君，东华帝君受之于金阙帝君，金阙帝君受之于西王母。西王母皆口口相传，不记文字。吾今于世，书而录之。上士悟之，升为天官；中士修之，南宫列仙；下士得之，在世长年。游行三界，升入金门。",note:"这一段主要建立经典的传授来源与信受权威。"},{speaker:"左玄真人",role:"护持功能",text:"学道之士，持诵此经者，即得十天善神，拥护其身。然后玉符保神，金液炼形。形神俱妙，与道合真。",note:"强调持诵后的护持与形神兼修。"},{speaker:"正一真人",role:"感应劝信",text:"人家有此经，悟解之者，灾障不干，众圣护门。神升上界，朝拜高真。功满德就，相感帝君。诵持不退，身腾紫云。",note:"更偏向感应、护门与劝信语气。"}]}),a[3]||(a[3]=e("h2",{id:"【原典层】字词释义",tabindex:"-1"},[n("【原典层】字词释义 "),e("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),i(d,{title:"字词释义",items:[{term:"澄",pinyin:["chéng"],meaning:"澄心之澄，有沉静、澄明之意。"},{term:"湛",pinyin:["zhàn"],meaning:"湛然常寂，偏向澄澈、深静而不昏滞。"},{term:"寂",pinyin:["jì"],meaning:"这里的寂偏向静定，不是死寂。"},{term:"悉",pinyin:["xī"],meaning:"悉皆归，即都归于其位。"},{term:"於",pinyin:["yú"],meaning:"於空的“於”，同“于”。"},{term:"道",pinyin:["dào"],meaning:"根本之道，不以固定形名被穷尽。",context:"经文一开始先说明：道不可被一句话完全定义，却始终生育万物。"},{term:"清静",pinyin:["qīng","jìng"],meaning:"清明、安定、澄定，不是僵住不动。",context:"全经最后都收回到“常应常静，常清静矣”的状态。"},{term:"心",pinyin:["xīn"],meaning:"念头活动、意识流转、内在扰动之处。",context:"人之所以不静，往往先是心自扰。"},{term:"神",pinyin:["shén"],meaning:"精神、灵明、清明之性。",context:"经文说“人神好清”，指出人本来就向往清明。"},{term:"欲",pinyin:["yù"],meaning:"牵引、执取、不断向外抓取的力量。",context:"遣欲不是粗暴压制，而是不再一路被欲牵着走。"},{term:"空",pinyin:["kōng"],meaning:"空其执，不是把一切抹成虚无。",context:"观空的重点在松开执著，而不是否定世界本身。"},{term:"真常",pinyin:["zhēn","cháng"],meaning:"真实而恒常，不是暂时出现的一阵清静感。",context:"真常应物，正说明真正的静并不离开现实万物。"},{term:"应物",pinyin:["yìng","wù"],meaning:"面对万物、回应万物而不失其根。",context:"这也是经文中最能把修持从“静坐状态”拉回日用的一句。"}]}),a[4]||(a[4]=c("",49))])}const y=s(g,[["render",u]]);export{P as __pageData,y as default};
